"""
MKT Original Commentary — Nehemiah chapters 5–6
Run: python3 scripts/zc-original-nehemiah-5-6.py

Ch 5: The economic crisis — oppression by nobles and Nehemiah's fiscal reforms
  - v1: ṣĕʿāqāh (covenant-cry of the oppressed; same root as Exod 3:7 / Gen 18:20)
  - v3,8: ʿrb (to pledge/become surety) and qnh (buy back) — the debt-slavery vocabulary
  - v5: kbš (subdue/enslave) — strong verb for what's being done to children
  - v7: ryb (to contend at law/bring formal charge) — legal-dispute term; mlk in Hithpoel (deliberate with oneself)
  - v10: cohortative + nāʾ expressing communal request, not coercion
  - v13: ḥōṣen (fold/pocket of garment) + nāʿar (shake out) — the enacted curse-gesture
  - v19: "Remember me with favor" — first of five zĕḵārāh-lî prayers in the book

Ch 6: Schemes against Nehemiah and the wall's completion
  - v1: perēṣ (breach/gap) — technical term for wall-integrity (cf. Ezek 22:30)
  - v3: melaʾkāh gĕdôlāh (great work) — same term as tabernacle/temple-work in Exod 36; yārad (come down) used twice as the metaphor for abandoning the task
  - v5: sefer pātûaḥ (unsealed letter) — deliberate public shaming via open document
  - v6: mrd (to rebel/commit treason) — the Persian-era weight of the accusation
  - v9: rpw yĕdêhem (slack hands = demoralized) ↔ ḥazzēq yādāy (strengthen my hands)
  - v10: ʿāṣûr (homebound/confined) — Shemaiah's staged restriction enhancing prophetic credibility
  - v12: lōʾ ʾĕlōhîm šĕlāḥô (God did not send him) — false-prophet discernment language
  - v15: The 52-day completion — a precise calendar claim (25th Elul)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "5": {
    "1": "<p><strong>ṣĕʿāqāh gĕdôlāh</strong> — the &lsquo;great outcry&rsquo; invokes a specific covenant-legal tradition: the <em>ṣĕʿāqāh</em> is the cry of the oppressed that obliges YHWH to respond (Exod 3:7: &lsquo;I have heard their <em>ṣĕʿāqāh</em>&rsquo;; Gen 18:20-21: the <em>ṣaʿăqat</em> of Sodom; Job 34:28). Its appearance in Nehemiah signals that the economic crisis reaches the level of the covenant-violation YHWH promised to address in Exod 22:23-24 (&lsquo;if you oppress them, and they cry out to me, I will surely hear their cry&rsquo;). The inclusion of <strong>wĕnāšêhem</strong> (and their wives) is notable — wives rarely appear as co-agents of complaint in OT legal narratives; their inclusion signals this is a whole-household emergency, not a peripheral grievance.</p>",
    "2": "<p>The Hebrew text of this verse is grammatically difficult. The phrase <strong>ûḇānênû ûḇĕnōtênû raḇbîm ʾănaḥnû</strong> can be parsed as &lsquo;our sons and daughters are many — we are&rsquo; (i.e., we are a large family, so we need grain to eat), but the LXX reads differently, suggesting some scribes understood the <em>raḇbîm</em> as a financial obligation rather than family size. The MKT renders it as &lsquo;our families are large.&rsquo; The complaint is economic at its base: many mouths to feed, insufficient grain, no cash reserves. The verb <strong>niqḥāh</strong> (imperative Qal of lqḥ, to take) in the form <em>we need to take grain</em> is a request-verb, not a demand — the people are asking for grain access, not seizing it.</p>",
    "3": "<p><strong>ʿāraḇnû</strong> — from the root <em>ʿrb</em> (to pledge, become surety; to be tangled/mixed). The Qal perfect &lsquo;we have pledged&rsquo; indicates a completed action. The three items pledged — fields, vineyards, and homes (<em>śĕdōtênû ûkarmêhem ûḇāttênû</em>) — represent the full rural asset base: arable land, viticulture, and housing. The impetus was <strong>wĕhāreʿāḇ</strong> (and the famine) — a short-term food crisis turned into long-term land-loss through the pledging mechanism. The verb <em>ʿrb</em> is also the root of the word for &lsquo;pledge/surety&rsquo; in Prov 17:18 and Gen 43:9 (Judah becoming surety for Benjamin), connecting to the broader covenant-solidarity vocabulary.</p>",
    "4": "<p><strong>lāwînû</strong> (we have borrowed) — root <em>lwh</em>, to borrow; the Qal perfect. The loan is specifically for tax payment (<strong>middāt hammelek</strong>, &lsquo;the king&rsquo;s tribute&rsquo;). The Persian provincial taxation system required payment in silver (as Ezra 4:13 specifies: <em>middāh</em>, <em>bĕlô</em>, <em>wahălāk</em> — tribute, customs, and toll), but the community had no silver reserves and had to borrow against their land to pay. The compounding effect: fields pledged to get grain (v3) + fields again to borrow silver for taxes (v4) + fields already mortgaged unable to generate income to repay = systematic debt-slavery. The <em>karmênû ûśĕdōtênû</em> (our vineyards and fields) appears here too — the same assets already pledged in v3 are now also pledged for the tax debt.</p>",
    "5": "<p><strong>kĕḇaśar ʾaḥêhem bĕśārênû</strong> (as our brothers&rsquo; flesh is our flesh) — the kinship-solidarity formula using <em>bāśār</em> (flesh/body) as the marker of shared humanity and covenant obligation. In covenant contexts, &lsquo;one flesh&rsquo; signals the strongest bond (Gen 2:24; Judg 9:2). The argument is: we are blood-kin, yet our children face what their children do not face.</p><p><strong>kōḇĕšîm</strong> (from <em>kbš</em>, to subdue, to bring under foot) — the participle is strong; the root is used of subduing enemies in battle (Num 32:22,29) and of subduing the earth in Gen 1:28. Applied to children being &lsquo;subdued&rsquo; into slavery by their own kinsmen, the word is a covenant-violation term at its most severe. The MKT renders it &lsquo;reduce... to slavery,&rsquo; but the image is more violent than mere labor: it is conquest-language applied to covenant kin.</p>",
    "6": "<p><strong>wayyiḥar lî mĕʾōd</strong> — literally &lsquo;it burned greatly for me.&rsquo; The idiom uses the root <em>ḥārāh</em> (to burn, to become hot) with the dative (<em>lî</em>) rather than the more common <em>ḥārāh ʾappô</em> (his nose burned = he was angry). The construction without <em>ʾap</em> (nose) but with <em>lî</em> (to me) is unusual — it may indicate an internalized fury rather than an outward expression. The adverb <em>mĕʾōd</em> (very much, greatly) intensifies the emotional state. The verse is a single, stark sentence after the long complaint-speeches of vv2-5, functioning as the narrator&rsquo;s pivot toward action.</p>",
    "7": "<p><strong>wayyimmalek lĕḇābî ʿālay</strong> — the Hithpoel of <em>mlk</em> (to be king, to take counsel) with &lsquo;my heart&rsquo; as subject is a rare construction meaning to deliberate inwardly or consult with oneself. The form expresses a reflexive consultation — Nehemiah&rsquo;s heart deliberated over him, advising him before he acted. The pause between anger (v6) and action is itself significant.</p><p><strong>wāʾrîḇāh</strong> — the Qal imperfect of <em>ryb</em> (to contend, to dispute at law, to bring a lawsuit). The verb is used throughout the prophets for YHWH&rsquo;s covenant lawsuit against Israel (Hos 4:1; Mic 6:2; Jer 2:9) and for legal contests between parties (Deut 17:8; 19:17). The MKT &lsquo;brought a formal charge&rsquo; captures the legal-contest nuance better than &lsquo;rebuked.&rsquo; Nehemiah is not merely expressing displeasure — he is initiating a legal process.</p>",
    "8": "<p><strong>qānîtî</strong> (I bought) — root <em>qnh</em> (to buy, acquire, possess). The same root underlies the kinsman-redeemer (<em>gōʾēl</em>) concept, though Nehemiah does not use the <em>gōʾēl</em> term here. The action of buying back Jewish kin from foreign nations (ĕlgôyim) directly invokes Lev 25:47-55 (the redemption of kin sold to a foreigner). The rhetorical move: Nehemiah&rsquo;s community spent resources to redeem exiles from foreign bondage; the nobles are now re-enslaving those same kin to get those resources back. The logic is self-defeating for covenant community integrity.</p><p><strong>gam-hēm tikmĕrû</strong> — &lsquo;so that they can be sold to us?&rsquo; The root <em>mkr</em> (to sell) in the Niphal/Qal; the question is biting: are you going to make us buy them back again?</p>",
    "9": "<p><strong>lēleket bĕyirʾat ʾĕlōhênû</strong> — the infinitive construct of <em>hlk</em> (to walk) with <em>bĕyirʾat</em> (in the fear of) is the Deuteronomic lifestyle-theology phrase; walking in the fear of God is the Hebrew equivalent of &lsquo;living faithfully.&rsquo; The <em>bĕ</em>-preposition (in/within the fear of God) places fear of God as the sphere of action, not merely an attitude. The argument is not primarily economic but covenantal: economic justice <em>is</em> what the fear of God looks like.</p><p><strong>ḥerpat haggôyim</strong> — the reproach of the nations; the community&rsquo;s economic misconduct damages the covenant people&rsquo;s testimony before their neighbors. The word <em>ḥerpāh</em> (reproach, shame) is the honor-vocabulary that recurs across Nehemiah (1:3; 2:17; 3:36; 5:9) — the whole wall-building project is about removing the <em>ḥerpāh</em> that Jerusalem&rsquo;s ruined state creates.</p>",
    "10": "<p><strong>naʿăzĕḇāh nāʾ</strong> — the cohortative (we should/let us) + <em>nāʾ</em> (particle of entreaty, please) makes Nehemiah&rsquo;s demand into a communal request: &lsquo;please, let us stop charging interest.&rsquo; The particle <em>nāʾ</em> softens the tone and invites collaborative action rather than imposing compliance. This is notable: Nehemiah does not command the nobles but invites them to join a communal standard he himself follows. The <em>maššāʾ</em> (burden, loan, interest) carries a double meaning — the financial loan and the social burden that the lending creates.</p>",
    "11": "<p><strong>maʾat hakkesep</strong> — translated as &lsquo;one-percent interest&rsquo; in many versions, but the exact rate is debated. The word <em>maʾat</em> can mean a hundredth (1%) or simply &lsquo;a portion&rsquo; without specifying the rate. The LXX and Vulgate also render the rate differently. The MKT &lsquo;one-percent interest&rsquo; follows the most common scholarly reading but with the caveat that the original may simply mean the prevailing interest rate (which in the ANE was often 20-25% annually for grain and 33% for silver). The demand to restore (<strong>hāšîḇû</strong>, Hiphil imperative of <em>šûḇ</em>) is the covenant-restoration verb — the same word used for Israel&rsquo;s return to YHWH; here it&rsquo;s economic restitution using the repentance-vocabulary.</p>",
    "12": "<p><strong>wayyōʾmĕrû</strong> (they said) followed by <strong>nāšîḇ</strong> (we will restore) and <strong>lōʾ-nĕḇaqqēš</strong> (we will not seek) — three consecutive cohortatives/imperfects expressing commitment. Nehemiah&rsquo;s immediate calling of the priests (<strong>hakkōhănîm</strong>) to administer the oath shows he did not trust verbal commitment alone. The <em>yiššāḇēʿûm</em> (he made them swear) is the Hiphil of <em>šbʿ</em> — the causative, meaning Nehemiah caused the nobles to swear by a formalized oath, which created a legally binding obligation in Israelite law (Lev 5:4; Num 30).</p>",
    "13": "<p><strong>ʾeṯ-ḥōṣnî</strong> — the fold or front of a garment used as a carrying-pouch; <em>nāʿar</em> (to shake out) creates an enacted curse-gesture: as the garment-fold is shaken empty, so let YHWH empty every person who breaks this oath. The enacted curse or oath-gesture is a well-attested ANE practice — the covenant-ceremony involving the cutting of animals in Gen 15 or the oath-gestures in Jer 34:18-19 (walking between the cut halves of the animal) used symbolic acts to make the oath&rsquo;s consequences vivid.</p><p><strong>wayyehî kaddāḇār hazzeh</strong> (let it be so/may it be done) — the community&rsquo;s ratification; the word <em>kaddāḇār</em> is &lsquo;like this word/thing,&rsquo; an affirmation of the enacted curse. The verb <strong>wayhallĕlû</strong> (they praised YHWH) reflects the covenant-affirmation that follows the oath — worship as the seal of the legal commitment.</p>",
    "14": "<p><strong>peḥat yĕhûdāh</strong> — the Persian loanword <em>peḥāh</em> (governor, from Old Persian <em>pitiḫa</em>, &lsquo;representative&rsquo;) combined with the province name; the title establishes Nehemiah&rsquo;s administrative authority. The twelve-year calculation (&lsquo;from the twentieth to the thirty-second year of King Artaxerxes&rsquo;) = 445-433 BCE — the precise Persian regnal-year dating is characteristic of the Nehemiah memoir&rsquo;s documentary style.</p><p><strong>ʾet-leḥem happeḥāh lōʾ ʾāḵaltî</strong> — &lsquo;the food of the governor I did not eat&rsquo; — the word order is emphatic (object first, then subject and verb), stressing <em>the governor&rsquo;s bread specifically</em> that Nehemiah refused. The governor&rsquo;s bread (<em>leḥem happeḥāh</em>) refers to the tax-in-kind that previous governors had exacted for their personal table — essentially a food-tribute on top of the silver taxes.</p>",
    "15": "<p><strong>wayyikbĕdû ʿal-hāʿām</strong> — &lsquo;they were heavy/burdensome upon the people&rsquo; — the verb <em>kāḇad</em> in the Qal (to be heavy) is the standard word for oppressive governance throughout the OT (cf. 1 Sam 5:6,11; 2 Sam 13:25). The specific figure of <strong>ʾarbaʿîm šeqel kesep</strong> (forty shekels of silver) as the daily food-and-wine allocation appears to be a tax-in-kind that previous governors extracted. Even their servants (<strong>naʿărêhem</strong>) exercised dominion (<strong>šālĕṭû</strong>, root <em>šlṭ</em> = to have dominion/authority) over the people — the governor&rsquo;s servants had derivative power over the population.</p><p><strong>mirrāʾat ʾĕlōhîm lōʾ ʿāśîtî kēn</strong> — &lsquo;but because of the fear of God, I did not act thus&rsquo; — the <em>yirʾat ʾĕlōhîm</em> (fear of God) from v9 returns as the stated motivation for Nehemiah&rsquo;s fiscal restraint. The fear of God is not merely a theological principle but the practical driver of administrative behavior.</p>",
    "16": "<p><strong>waḥazaqtî ûmal&lsquo;aḵtî</strong> — &lsquo;I gave myself fully to the work&rsquo; (literally &lsquo;I strengthened myself in/on the work&rsquo;) — the verb <em>ḥzq</em> in the Hithpael (reflexive-intensive) means to strengthen oneself; the reflexive use indicates Nehemiah&rsquo;s active self-application to the wall-building. The emphatic addition <strong>lōʾ qānîtî śādeh</strong> (I did not buy any land) is significant: land-acquisition by officials using their administrative position was a common form of corruption; Nehemiah explicitly refused it.</p>",
    "17": "<p><strong>wĕhayĕhûdîm wĕhaśśĕgānîm</strong> — &lsquo;the Jewish officials&rsquo; — <em>śāgān</em> (official/prefect) is an Akkadian loanword appearing across the late OT literature (Ezra, Nehemiah, Jer, Ezek) for civil officials; distinct from the <em>śārîm</em> (nobles) and <em>ḥōrîm</em> (freemen). The 150 officials at Nehemiah&rsquo;s daily table, plus visitors from surrounding nations, is a substantial hospitality obligation — his point is that he bore the full cost from his personal resources rather than from tax revenue.</p>",
    "18": "<p>The daily table provision — one ox (<em>šôr ʾeḥād</em>), six prime sheep (<em>ṣōʾn bĕrûrôt šēš</em>), birds, and wine every ten days — is an elaborate itemization that mirrors ancient Near Eastern administrative records of daily provisions for royal officials. The emphasis on <em>wine every ten days</em> (<em>bĕʿaśôr yāmîm</em>) specifies a particular luxury portion. <strong>bĕkol-zōʾt</strong> (despite all this) — the adversative conjunction highlighting the contrast: all this expense, yet <strong>lōʾ bāqqaštî ʾet-leḥem happeḥāh</strong> (I did not demand the governor&rsquo;s food allowance) — the formal right he had but voluntarily waived.</p>",
    "19": "<p><strong>zĕḵārāh-lî ʾĕlōhay lĕṭôḇāh</strong> — the first of five &lsquo;remember me&rsquo; prayers in Nehemiah (5:19; 6:14; 13:14; 13:22; 13:31). The Qal imperative <em>zĕḵār</em> (remember) addressed directly to God is not a demand but a covenantal appeal — YHWH&rsquo;s remembering is his saving attention to the covenant (Gen 8:1: &lsquo;God remembered Noah&rsquo;; 1 Sam 1:19: &lsquo;YHWH remembered Hannah&rsquo;). The dative <em>lî</em> (for me) specifies the direction of the remembrance; <strong>lĕṭôḇāh</strong> (for good/as a good thing) specifies its quality — favorable, beneficent remembering. The phrase <em>ʾăšer ʿāśîtî ʿal-hāʿām hazzeh</em> (all I have done for this people) grounds the petition in the record of covenant service rather than in a claim of merit.</p>"
  },
  "6": {
    "1": "<p><strong>perēṣ lōʾ-niwttar bāh</strong> — the wall is complete and &lsquo;no breach remained in it&rsquo; — <em>perēṣ</em> (breach, gap, rupture) is the technical term for wall-integrity. The root <em>prṣ</em> can mean to burst through, to spread/break out (2 Sam 5:20: YHWH &lsquo;burst out&rsquo; against the Philistines). In Ezek 22:30, YHWH sought someone to stand in the <em>perēṣ</em> (breach) before him; Nehemiah has achieved what the prophet described — the breach is filled. However, <strong>ûdĕlātôt lōʾ hĕʿĕmadtî</strong> (I had not set up doors in the gates) — the wall is continuous but incomplete; the gates cannot yet be locked. This detail explains why the enemies acted quickly.</p>",
    "2": "<p><strong>wayyiššĕlĕḥû</strong> (they sent) + <strong>nôʿădāh</strong> (let us meet by appointment) — the root <em>yāʿad</em> (to set a time, meet by appointment) is the verb for assembly and for trysts; in the wilderness narrative, the &lsquo;tent of meeting&rsquo; (<em>ʾōhel môʿēd</em>) uses the same root. The meeting proposed in the plain of Ono has the grammatical form of collegial consultation but Nehemiah reads its purpose differently: <strong>lôʾ-ṭôḇāh hēmmāh ḥōšĕḇîm laʿăśôt lî</strong> (&lsquo;they were planning to do me harm&rsquo;) — the verb <em>ḥšb</em> (to think/plan) combined with <em>rāʿāh</em> (evil) is the conspiracy vocabulary used throughout the wisdom literature.</p>",
    "3": "<p><strong>melaʾkāh gĕdôlāh ʾănî ʿōśeh</strong> — &lsquo;I am engaged in a great work.&rsquo; <em>Melaʾkāh</em> (work, task, commissioned project) is the same word used for the tabernacle construction (Exod 36:2,4,5,6,7,8) and the temple-building (1 Kgs 7:14; 1 Chr 29:1); by using this term, Nehemiah implicitly places his wall-building in the category of sacred construction. The rhetorical question <strong>lāmmāh tiŝbōt hammĕlaʾkāh wĕyāradtî ʾălêhem</strong> (&lsquo;why should the work stop while I come down to you?&rsquo;) uses <em>yārad</em> (to go down/descend) for the proposed journey; the verb is also the metaphor for abandoning one&rsquo;s elevated position or calling. Nehemiah will not &lsquo;come down&rsquo; — physically or spiritually — from the sacred task.</p>",
    "4": "<p><strong>ʾarbaʿ pĕʿāmîm kaddāḇār hazzeh</strong> — &lsquo;four times like this same thing&rsquo; — the iterative repetition (four times the same message, four times the same reply) is a narrative technique in the Hebrew prose style for showing persistent pressure and equally persistent refusal. The word <em>pĕʿāmîm</em> (times, occasions) is the standard word for repeated actions (cf. Gen 43:10: &lsquo;we could have gone there twice by now&rsquo;). The sameness of the answer (<em>kaddāḇār hazzeh</em>, &lsquo;like this word&rsquo;) emphasizes Nehemiah&rsquo;s consistent refusal — four iterations without wavering.</p>",
    "5": "<p><strong>sefer pātûaḥ</strong> — an &lsquo;open/unsealed letter&rsquo; was a deliberate public shaming tactic. In the ancient Near East, letters were sealed with clay tablets, wax, or cord-and-clay to ensure confidentiality and authenticate the sender. An unsealed letter was accessible to anyone who handled it along the way — porters, gatekeepers, bystanders. Sending an unsealed letter with damaging accusations was a calculated humiliation: it made the contents public knowledge before Nehemiah could respond. The aide (<em>naʿărô</em>, his servant/boy) was Sanballat&rsquo;s junior envoy, not a senior official — another slight in the mode of delivery.</p>",
    "6": "<p><strong>timrōd</strong> (you are planning to rebel) — root <em>mrd</em> (to rebel, revolt), the verb for political insurrection (Gen 14:4: &lsquo;the kings rebelled&rsquo;; Josh 22:16-19: the confrontation about the altar as potential rebellion). In the Persian administrative context, the accusation of <em>mĕrîdāh</em> (rebellion) was extremely serious — it could justify military intervention and execution. Artaxerxes had already halted the Jerusalem building project due to just such an accusation in Ezra 4:12-16. The letter is not merely diplomatic pressure but a legal threat: we have grounds to report you to the king as a traitor.</p>",
    "7": "<p><strong>ʾăšer-melaḵîm bîhûdāh</strong> — &lsquo;there is a king in Judah&rsquo; — the accusation adds a prophetic dimension: Nehemiah has appointed prophets to proclaim his kingship. The verb <em>qārāʾ</em> (to proclaim/call out) is the standard word for prophetic proclamation. The double accusation — you plan to revolt, and you have hired prophets to legitimize it — is a comprehensive treason charge. <strong>wĕʿattāh</strong> (and now) is the consequence-clause, standard in ANE political correspondence: &lsquo;given all this, come now and let us discuss it together.&rsquo; The invitation is framed as crisis management, but it is a trap.</p>",
    "8": "<p><strong>lōʾ-nihĕyu haddĕḇārîm hāʾēlleh kāʾăšer ʾattāh ʾômēr</strong> — &lsquo;none of these things happened as you say&rsquo; — a flat denial using the perfect tense (<em>nihĕyu</em>, &lsquo;were not&rsquo;/&lsquo;did not happen&rsquo;), not a qualified defense. <strong>millib-bĕkā ʾattāh bādēʾm</strong> — &lsquo;from your heart you are fabricating/inventing them&rsquo; — the verb <em>bādāh</em> (to invent, make up) appears only a few times in the OT (1 Kgs 12:33: Jeroboam &lsquo;invented a festival from his own heart&rsquo;); the attribution <em>millib-bĕkā</em> (from your heart) locates the fabrication entirely in Sanballat&rsquo;s own imagination, not in any evidence. The accusation is pure invention.</p>",
    "9": "<p><strong>kî kullām mĕyarʾîm ʾôtānû</strong> — &lsquo;for they were all trying to frighten us&rsquo; — the Piel participle of <em>yrʾ</em> (to fear) in the causative sense (to make fear, to frighten). <strong>yirpenû yĕdêhem</strong> — &lsquo;so our hands would go limp&rsquo; — the verb <em>rāpāh</em> (to be slack, weak, feeble; cf. Heb 12:12: &lsquo;lift up your drooping hands&rsquo;) in the Qal imperfect; slack hands is the Hebrew idiom for demoralization and abandonment of a task. The countermeasure is the arrow-prayer: <strong>ḥazzēq ʾeṯ-yādāy</strong> (&lsquo;strengthen my hands&rsquo;) — the Piel imperative of <em>ḥzq</em>, requesting the direct opposite of what the enemy intended. The prayer is five words in Hebrew — the entire verse&rsquo;s theology in a flash-petition.</p>",
    "10": "<p><strong>wĕhûʾ ʿāṣûr</strong> — &lsquo;and he was confined/homebound&rsquo; — the Qal passive of <em>ʿṣr</em> (to restrain, detain, be confined). The same root is used for imprisoned officials (Gen 39:20: Joseph imprisoned) and for ritual confinement (Lev 13:5: the priest confines the person with skin disease). Shemaiah&rsquo;s confinement could signal ritual purity (making him seem more prophetically credible), claimed illness (giving the meeting an urgency), or staged drama (the private sanctuary meeting was more compelling if the prophet was already in a heightened state). The word <em>ʿāṣûr</em> alone does not tell us which.</p>",
    "11": "<p><strong>ûmî kāmônî ʾăšer-yāḇôʾ ʾel-hahêkāl wāḥāy</strong> — &lsquo;and who, like me, would enter the temple and live?&rsquo; — the issue is priestly purity law: entering the sanctuary interior was restricted to priests; for a layman to enter was to die (Num 18:7: &lsquo;the outsider who comes near shall be put to death&rsquo;). Nehemiah was not a priest; entering the sanctuary (hêkāl, the nave/main hall, not merely the court) to hide would have been a capital offense under priestly law. The argument has two levels: (1) it is undignified for a leader to flee; (2) the proposed refuge would itself be a sin. The double refusal makes flight impossible on both honor and legal grounds.</p>",
    "12": "<p><strong>wĕhinnēh lōʾ ʾĕlōhîm šĕlāḥô</strong> — &lsquo;and behold, God had not sent him&rsquo; — the discernment formula for identifying false prophecy. The criterion <em>YHWH/God had not sent him</em> is the definitive test in Jer 23:21 (&lsquo;I did not send these prophets, yet they ran&rsquo;), Jer 27:15; 28:15; Ezek 13:6. <strong>kî hattôbîyāh wĕsanballat śĕḵārûhû</strong> (&lsquo;because Tobiah and Sanballat had hired him&rsquo;) — the Qal perfect of <em>śkr</em> (to hire) reveals the financial mechanism behind the false prophecy. A hired prophet (<em>nāḇîʾ śāḵîr</em>) is categorically delegitimized — the mercenary motive corrupts the message entirely (cf. Mic 3:11: prophets who divine for money).</p>",
    "13": "<p><strong>lĕmaʿan ʾîrāʾ wĕʾeʿĕśeh-kēn wĕḥāṭāʾtî</strong> — &lsquo;so that I would be afraid and act accordingly, and so sin&rsquo; — the causal chain: fear → action → sin. The verb <em>ḥāṭāʾ</em> (to sin, miss the mark) identifies the proposed action (entering the sanctuary) as a formal covenant violation, not merely a social embarrassment. <strong>wĕhāyāh lāhem lĕšēm rāʿ</strong> (so that they could give me a bad reputation) — the motive of reputation-damage through inducing a specific sin that could then be publicly reported. The enemies&rsquo; tactic is sophisticated: use a paid prophet to create a situation where Nehemiah either commits a sin (entering the sanctuary = priestly privilege) or is seen as a coward (fleeing to it).</p>",
    "14": "<p><strong>zĕḵārāh ʾĕlōhay lĕṭôḇîyāh ûlĕsanballaṭ</strong> — the second &lsquo;remember me&rsquo; prayer (cf. 5:19), but now inverted: remember <em>them</em> for judgment. The word <em>zĕḵārāh</em> is the same imperative as 5:19 but directed against enemies rather than on behalf of Nehemiah; the prayer form is the same, the content is imprecatory. <strong>nôʿadyāh hanĕḇîʾāh</strong> (the prophetess Noadiah) — a female prophet among the opposition, unique in the Nehemiah narrative; the mention of a female prophet attempting to frighten Nehemiah is a rare glimpse of women in prophetic roles in the post-exilic community, even in opposition.</p>",
    "15": "<p><strong>bĕʿeśrîm waḥămiššāh lĕʾĕlûl</strong> — the precise dating (25th of Elul, the 6th month) combined with the <strong>ḥămiššîm ûšĕnayim yôm</strong> (52 days) is one of Nehemiah&rsquo;s most specific historical claims. Elul = August-September. The 52-day duration (from beginning of construction to completion of the wall — though gaps and gates remained) is extraordinarily fast; it was subsequently noted by Josephus as remarkable. The specificity of the date serves both as a historical record and as evidence for divine assistance — what took years for other projects was accomplished in less than two months.</p>",
    "16": "<p><strong>wayyippĕlû mĕʾōd bĕʿênêhem</strong> — literally &lsquo;they fell greatly in their eyes&rsquo; — the idiom of falling in one&rsquo;s own eyes (<em>ʿênêhem</em>, their eyes) means self-devaluation or profound shame. The enemies&rsquo; confidence (<em>bĕṭaḥôn</em>) collapsed because they recognized the achievement as divine rather than merely human: <strong>wayyēdĕʿû kî mēʾet ʾĕlōhênû neʿĕśĕtāh hammĕlaʾkāh hazzōʾt</strong> (&lsquo;for they knew that this work had been accomplished with the help of our God&rsquo;). The Niphal <em>neʿĕśĕtāh</em> (was accomplished/was done) has a passive-divine nuance: the work was done, implying it was done through/by them but ultimately by God. The enemies&rsquo; recognition of divine agency is an indirect acknowledgment of YHWH&rsquo;s power.</p>",
    "17": "<p><strong>wûḇayyāmîm hāhēm</strong> — &lsquo;also during that period&rsquo; — the temporal marker indicates a concurrent development alongside the wall-building. The &lsquo;nobles of Judah&rsquo; (<em>ḥōrê yĕhûdāh</em>) — the freemen/aristocrats of the community — were sending numerous letters to Tobiah and receiving replies. The verb <em>hōlĕkôt</em> (going, coming and going) suggests an ongoing correspondence, not a single exchange. The <em>ḥōrîm</em> (freemen, nobles) are distinct from the <em>śĕgānîm</em> (officials) — this is the upper crust of Judean society maintaining diplomatic ties with the external opponent.</p>",
    "18": "<p><strong>kî-raḇbîm bîhûdāh baʿălê šĕḇûʿô</strong> — &lsquo;for many in Judah were bound to him by oath&rsquo; — the <em>baʿălê šĕḇûʿô</em> (masters/owners of his oath) is an unusual phrase; it means &lsquo;those who had taken an oath with him,&rsquo; i.e., those who were parties to a binding agreement with Tobiah. The double marriage-connection (<em>Tobiah = son-in-law of Shecaniah son of Arah; his son Jehohanan = married daughter of Meshullam son of Berechiah</em>) reveals why the aristocratic community maintained ties with the opposition: Tobiah was family to two of the most prominent Judean families.</p>",
    "19": "<p><strong>ṭôḇōtāyw</strong> — &lsquo;his good deeds&rsquo; — the word <em>ṭôḇōtāyw</em> (his acts of good/his benefits) from <em>ṭôḇ</em> has an ironic weight in this context: the same root (<em>ṭôḇāh</em>) appears in Nehemiah&rsquo;s &lsquo;remember me for good&rsquo; prayers (5:19; 13:31). The nobles were presenting Tobiah&rsquo;s <em>ṭôḇôt</em> before Nehemiah, while Nehemiah prayed for YHWH&rsquo;s <em>ṭôḇāh</em> (favor) on himself — the same word in opposing directions. <strong>wĕdĕḇāray hāyû môṣîʾîm lô</strong> (and my words were being reported to him) — the Hiphil participle of <em>yṣʾ</em> (to bring out, report back); Tobiah had an intelligence pipeline directly from Nehemiah&rsquo;s circle through the nobles who functioned as unwitting spies.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'nehemiah')
    merge_comm(existing, ORIGINAL)
    save_comm('mkt-original', 'nehemiah', existing)
    total = sum(len(vv) for vv in ORIGINAL.values())
    print(f'Nehemiah 5-6 mkt-original written ({total} verses: ch5={len(ORIGINAL["5"])}, ch6={len(ORIGINAL["6"])}).')

if __name__ == '__main__':
    main()
